   226→/**
   227→ * Build the summarization prompt for a documentation file.
   228→ * Note: File path is intentionally omitted to prevent AI agents from
   229→ * attempting to explore/read the file instead of just summarizing the content.
   230→ */
   231→function buildSummarizationPrompt(content: string): string {
   232→	return `You are a documentation summarizer for AI coding agents.
   233→
   234→Given the following Markdown documentation, provide a single detailed sentence that describes both the document's purpose and the key information it contains for developers/AI agents.
   235→
   236→IMPORTANT:
   237→- Respond with ONLY 1 detailed sentence, nothing else
   238→- Be specific and actionable, avoid vague statements
   239→- Focus on information useful for coding tasks
   240→
   241→---
   242→
   243→\`\`\`markdown
   244→${content}
   245→\`\`\``;
   246→}
   247→
   248→/**
   249→ * Generate a single detailed sentence summary for a documentation file.
   250→ *
   251→ * Uses isolated prompt execution to prevent AI agents from exploring
   252→ * the filesystem instead of just summarizing the provided content.
   253→ *
   254→ * @param relativePath - Relative path for display (used in fallback message only)
   255→ * @param content - File content to summarize
   256→ * @param provider - AI provider for summarization
   257→ * @param timeout - Timeout in milliseconds (default: 60000)
   258→ * @returns Summary string (1 detailed sentence)
   259→ */
   260→export async function summarizeDocFile(
   261→	relativePath: string,
   262→	content: string,
   263→	provider: IAIProvider,
   264→	timeout?: number,
   265→	verbose?: boolean,
   266→): Promise<string> {
   267→	const prompt = buildSummarizationPrompt(content);
   268→
   269→	try {
   270→		// Use isolated execution with lightweight model to prevent file exploration
   271→		const response = await invokeIsolated(provider, prompt, {
   272→			timeout: timeout ?? DEFAULT_TIMEOUT_MS,
   273→			useLightweightModel: true,
   274→			verbose,
   275→		});
   276→
   277→		// Clean up the response - remove any extra whitespace/newlines
   278→		const summary = response.result.trim();
   279→
   280→		// Validate it looks like a summary (has some content)
   281→		if (summary.length < 10) {
   282→			return `Documentation file at ${relativePath}. Summary unavailable.`;
   283→		}
   284→
   285→		return summary;
   286→	} catch (_error) {
   287→		// Fallback on error
   288→		return `Documentation file at ${relativePath}. Summary unavailable.`;
   289→	}
   290→}
   291→
   292→/**
   293→ * Read file content with optional truncation
   294→ */
   295→async function readFileWithLimit(
   296→	filePath: string,
   297→	maxLength: number,
   298→): Promise<string | null> {
   299→	try {
   300→		const content = await readFile(filePath, "utf-8");
   301→
   302→		if (content.length > maxLength) {
   303→			// Truncate at a newline boundary if possible
   304→			const truncated = content.slice(0, maxLength);
   305→			const lastNewline = truncated.lastIndexOf("\n");
   306→
   307→			return lastNewline > maxLength * 0.8
   308→				? `${truncated.slice(0, lastNewline)}\n\n[Content truncated...]`
   309→				: `${truncated}\n\n[Content truncated...]`;
   310→		}
   311→
   312→		return content;
   313→	} catch {
   314→		return null; // File not found or read error
   315→	}
   316→}
   317→
   318→/**
   319→ * Discover and summarize linked documentation from AGENTS.md files.
   320→ * Finds all .md files linked from the provided AGENTS.md files,
   321→ * reads their content, and generates AI summaries.
   322→ *
   323→ * @param agentsFiles - Absolute paths to AGENTS.md/CLAUDE.md files
   324→ * @param baseDir - Repository base directory
   325→ * @param options - Discovery options
   326→ * @returns Discovery result with summarized docs
   327→ */
   328→export async function discoverLinkedDocs(
   329→	agentsFiles: string[],
   330→	baseDir: string,
   331→	options: IDocDiscoveryOptions,
   332→): Promise<ILinkedDocsResult> {
   333→	const {
   334→		provider,
   335→		verbose = false,
   336→		maxDocs = 30,
   337→		maxContentLength = 8000,
   338→		concurrency = 2,
   339→	} = options;
   340→
   341→	const allLinks: IExtractedLink[] = [];
   342→	const unresolvedLinks: string[] = [];
   343→
   344→	// Step 1: Extract links from all AGENTS.md files
   345→	for (const agentsFile of agentsFiles) {
   346→		try {
   347→			const content = await readFile(agentsFile, "utf-8");
   348→			const links = extractMarkdownLinks(content, agentsFile);
   349→
   350→			if (verbose && links.length > 0) {
   351→				console.log(
   352→					`[DocsFinder] Found ${links.length} link(s) in ${getRelativePath(agentsFile, baseDir)}`,
   353→				);
   354→			}
   355→
   356→			allLinks.push(...links);
   357→		} catch (error) {
   358→			if (verbose) {
   359→				console.log(`[DocsFinder] Error reading ${agentsFile}:`, error);
   360→			}
   361→		}
   362→	}
   363→
   364→	// Step 2: Deduplicate links (same target from different sources)
   365→	const uniqueLinks = new Map<string, IExtractedLink>();
   366→	for (const link of allLinks) {
   367→		// Keep the first occurrence (typically from root AGENTS.md)
   368→		if (!uniqueLinks.has(link.absolutePath)) {
   369→			uniqueLinks.set(link.absolutePath, link);
   370→		}
   371→	}
   372→
   373→	const deduplicatedLinks = Array.from(uniqueLinks.values());
   374→	const totalLinksFound = deduplicatedLinks.length;
   375→
   376→	if (verbose) {
   377→		console.log(
   378→			`[DocsFinder] ${totalLinksFound} unique linked doc(s) found after deduplication`,
   379→		);
   380→	}
   381→
   382→	// Step 3: Limit to maxDocs (prioritize links from root AGENTS.md)
   383→	// Links are already ordered by source file, so we just take the first N
   384→	const linksToProcess = deduplicatedLinks.slice(0, maxDocs);
   385→
   386→	if (verbose && totalLinksFound > maxDocs) {
   387→		console.log(
   388→			`[DocsFinder] Limiting to ${maxDocs} docs (${totalLinksFound - maxDocs} skipped)`,
   389→		);
   390→	}
   391→
   392→	// Step 4: Read and summarize each linked doc
   393→	const docs: ILinkedDocSummary[] = [];
   394→
   395→	const summarizeLink = async (link: IExtractedLink): Promise<void> => {
   396→		const content = await readFileWithLimit(
   397→			link.absolutePath,
   398→			maxContentLength,
   399→		);
   400→
   401→		if (content === null) {
   402→			unresolvedLinks.push(link.rawPath);
   403→			if (verbose) {
   404→				console.log(`[DocsFinder] File not found: ${link.rawPath}`);
   405→			}
   406→			return;
   407→		}
   408→
   409→		const relativePath = getRelativePath(link.absolutePath, baseDir);
   410→		const linkedFrom = getRelativePath(link.sourcePath, baseDir);
   411→
   412→		if (verbose) {
   413→			console.log(`[DocsFinder] Summarizing: ${relativePath}`);
   414→		}
   415→
   416→		const summary = await summarizeDocFile(
   417→			relativePath,
   418→			content,
   419→			provider,
   420→			options.timeout,
   421→			verbose,
   422→		);
   423→
   424→		docs.push({
   425→			path: relativePath,
   426→			summary,
   427→			linkedFrom,
   428→			content, // Include content for preview in browser modal
   429→		});
   430→	};
   431→
   432→	// Process links with concurrency control
   433→	await runWithConcurrencyLimit(linksToProcess, concurrency, (link) =>
   434→		summarizeLink(link),
   435→	);
   436→
   437→	if (verbose) {
   438→		console.log(
   439→			`[DocsFinder] Successfully summarized ${docs.length} doc(s), ${unresolvedLinks.length} unresolved`,
   440→		);
   441→	}
   442→
   443→	return {
   444→		docs,
   445→		totalLinksFound,
   446→		unresolvedLinks,
   447→	};
   448→}
   449→

